function roundToCents(value) {
  return Math.round(value * 100) / 100;
}

function calculateSubtotal(items) {
  let subtotal = 0;
  for (let i = 0; i < items.length; i++) {
    subtotal += items[i].price * items[i].qty;
  }
  return subtotal;
}

function calculateDiscount(order, subtotal) {
  let discount = 0;
  if (order.coupon) {
    if (order.coupon === 'SAVE10') {
      discount = subtotal * 0.1;
    } else if (order.coupon === 'SAVE20') {
      if (subtotal >= 100) {
        discount = subtotal * 0.2;
      } else {
        discount = subtotal * 0.1;
      }
    } else if (order.coupon === 'HALF' && order.vip) {
      discount = subtotal * 0.5;
    }
  }
  if (order.vip && discount < subtotal * 0.05) {
    discount = subtotal * 0.05;
  }
  return discount;
}

function calculateTax(region, taxed) {
  let tax = 0;
  if (region === 'US') {
    tax = taxed * 0.07;
  } else if (region === 'EU') {
    tax = taxed * 0.2;
  } else {
    tax = taxed * 0.1;
  }
  return tax;
}

function calculateShipping(order, taxed) {
  let shipping = 0;
  if (taxed < 50) {
    shipping = 7.5;
  } else if (taxed < 100) {
    shipping = 3;
  } else {
    shipping = 0;
  }
  if (order.express) {
    shipping += 12;
  }
  return shipping;
}

export function calculateInvoice(order) {
  let subtotal = calculateSubtotal(order.items);
  let discount = calculateDiscount(order, subtotal);
  let taxed = subtotal - discount;
  let tax = calculateTax(order.region, taxed);
  let shipping = calculateShipping(order, taxed);
  let total = taxed + tax + shipping;
  return {
    subtotal: roundToCents(subtotal),
    discount: roundToCents(discount),
    tax: roundToCents(tax),
    shipping: roundToCents(shipping),
    total: roundToCents(total),
  };
}

